  <title>OpenFons 最佳实践架构图</title>
  <style>
    @font-face {
      font-family: "OpenFons Sans";
      src:
        local("IBM Plex Sans"),
        local("Noto Sans SC"),
        local("PingFang SC"),
        local("Microsoft YaHei UI"),
        local("Microsoft YaHei"),
        local("Segoe UI");
      font-display: swap;
    }

    :root {
      --bg: #f4efe7;
      --panel: #fffdf9;
      --ink: #152127;
      --muted: #4d5a60;
      --line: rgba(21, 33, 39, 0.12);
      --shadow: 0 18px 45px rgba(21, 33, 39, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      background:
        radial-gradient(circle at top left, rgba(217, 107, 43, 0.08), transparent 28%),
        radial-gradient(circle at top right, rgba(47, 95, 227, 0.08), transparent 25%),
        linear-gradient(180deg, #f7f2eb 0%, var(--bg) 100%);
      color: var(--ink);
      font-family: "OpenFons Sans", "Noto Sans SC", "PingFang SC", "Microsoft YaHei", "Segoe UI", sans-serif;
      line-height: 1.6;
    }

    .page {
      width: min(1320px, calc(100vw - 32px));
      margin: 0 auto;
      padding: 28px 0 56px;
      display: grid;
      gap: 18px;
    }

    .intro {
      padding: 22px 24px;
      border-radius: 24px;
      border: 1px solid var(--line);
      box-shadow: var(--shadow);
      background:
        radial-gradient(circle at top right, rgba(47, 95, 227, 0.10), transparent 28%),
        linear-gradient(180deg, #fffaf2 0%, #fff4e8 100%);
    }

    .intro h1 {
      margin: 0 0 8px;
      font-size: clamp(30px, 4vw, 50px);
      line-height: 1.08;
      letter-spacing: -0.04em;
    }

    .subtitle {
      max-width: 920px;
      margin: 0 0 14px;
      color: var(--muted);
    }

    .key-line {
      display: inline-flex;
      flex-wrap: wrap;
      gap: 8px;
      align-items: center;
      padding: 10px 12px;
      border-radius: 16px;
      background: rgba(21, 33, 39, 0.05);
      font-size: 13px;
      color: var(--muted);
    }

    .plane-stack {
      display: grid;
      gap: 14px;
    }

    .plane {
      display: grid;
      grid-template-columns: 240px 1fr 260px;
      gap: 14px;
      padding: 18px;
      border-radius: 24px;
      border: 1px solid var(--line);
      box-shadow: var(--shadow);
      background: var(--panel);
    }

    .plane.access {
      background: linear-gradient(180deg, #fffaf3 0%, #fff1dd 100%);
    }

    .plane.control {
      background: linear-gradient(180deg, #f7f9ff 0%, #e9efff 100%);
    }

    .plane.execution {
      background: linear-gradient(180deg, #f2fbf8 0%, #e3f4ef 100%);
    }

    .plane.data {
      background: linear-gradient(180deg, #fcfbf3 0%, #f4efd8 100%);
    }

    .plane-tag {
      display: inline-block;
      padding: 6px 10px;
      border-radius: 999px;
      background: rgba(21, 33, 39, 0.08);
      font-size: 11px;
      font-weight: 700;
      letter-spacing: 0.04em;
      text-transform: uppercase;
    }

    .plane h2 {
      margin: 10px 0 6px;
      font-size: 21px;
    }

    .plane p {
      margin: 0;
      color: var(--muted);
    }

    .step-row {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
      gap: 10px;
      align-content: start;
    }

    .step-card {
      min-height: 102px;
      padding: 12px;
      border-radius: 18px;
      border: 1px solid rgba(21, 33, 39, 0.10);
      background: rgba(255, 255, 255, 0.82);
    }

    .step-card strong {
      display: block;
      margin-bottom: 6px;
      font-size: 14px;
    }

    .step-card p {
      font-size: 13px;
      line-height: 1.5;
    }

    .borrow-box {
      padding: 12px 13px;
      border-radius: 18px;
      border: 1px dashed rgba(21, 33, 39, 0.16);
      background: rgba(255, 255, 255, 0.62);
      font-size: 13px;
      color: #536167;
    }

    .borrow-box strong {
      display: block;
      margin-bottom: 6px;
      color: var(--ink);
    }

    .footer-strip {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }

    .footer-note {
      padding: 16px;
      border-radius: 20px;
      border: 1px solid var(--line);
      box-shadow: var(--shadow);
      background: #fff;
    }

    .footer-note h2 {
      margin: 0 0 8px;
      font-size: 16px;
    }

    .footer-note p {
      margin: 0;
      color: #56656b;
      font-size: 13px;
      line-height: 1.6;
    }

    code {
      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      font-size: 0.95em;
    }

